#include <bits/stdc++.h>
using namespace std;
char s1[102],s2[102];
int n1,n2,l1,l2;
long long f[102][31];
int main(){
    while(cin>>s2>>n2>>s1>>n1){
        l1=strlen(s1),l2=strlen(s2);
        bool flag=false;
        for(int i=0;i<l1;i++){
            int pos=i;
            f[i][0]=0;
            for(int j=0;j<l2;j++){
                int cnt=0;
                while(s1[pos]!=s2[j]){
                    pos=(pos+1)%l1;
                    if(++cnt>=l1){
                        printf("0\n");
                        flag=1;
                        break;
                    }
                }
                pos=(pos+1)%l1;
                f[i][0]+=cnt+1;
                if(flag)
                    break;
            }
            if(flag)
                break;
        }
        if(flag)
            continue;
        for(int j=1;j<=30;j++)
            for(int i=0;i<l1;i++)
                f[i][j]=f[i][j-1]+f[(i+f[i][j-1])%l1][j-1];
        long long x=0,ans=0;
        for(int i=30;i>=0;i--)
            if(x+f[x%l1][i]<=l1*n1)
                x+=f[x%l1][i],ans+=1<<i;
        printf("%lld\n",ans/n2);
    }
    return 0;
}
